// Parse the response JSON to get the icons array
const responseData = pm.response.json();
const icons = responseData.icons;

// Save the icons array to a collection variable
pm.collectionVariables.set("availableIcons", JSON.stringify(icons));

// Log the saved icons for verification
console.log("Saved icons to collection variable 'availableIcons':");
console.log(icons);

// Retrieve the availableIcons collection variable
const iconsJson = pm.collectionVariables.get("availableIcons");
const icons = JSON.parse(iconsJson);

// Function to get random items from an array
function getRandomItems(arr, count) {
    const shuffled = [...arr].sort(() => 0.5 - Math.random());
    return shuffled.slice(0, count);
}

// Select 3 random icons from the array
const randomIcons = getRandomItems(icons, 3);

// Join the icons with spaces - they already have colons in their names
const displayText = randomIcons.join(" ");

// Save this text to a collection variable called "displayText"
pm.collectionVariables.set("displayText", displayText);

// Log for verification
console.log("Selected random icons:", randomIcons);
console.log("Display text:", displayText);
